const PATENT_PRESET_KEYS = PATENT_PRESET_DEFINITIONS.map((preset) => preset.key);

const normalizePrescription = (prescription = {}) => {
  if (prescription.prescriptionType === "surface") {
    return {
      prescriptionType: "surface",
      focalLength: normalizePatentSurfaceValue(prescription.focalLength),
      apertureRatio: prescription.apertureRatio ?? null,
      fNumber: normalizePatentSurfaceValue(prescription.fNumber),
      backFocalLength: normalizePatentSurfaceValue(prescription.backFocalLength),
      fieldAngleDeg: normalizePatentSurfaceValue(prescription.fieldAngleDeg),
      imageFormat: prescription.imageFormat ?? null,
      sourcePatent: prescription.sourcePatent ?? null,
      example: prescription.example ?? null,
      patentDataStatus: prescription.patentDataStatus ?? null,
      presetGroup: prescription.presetGroup || null,
      sourceExample: prescription.sourceExample || null,
      normalizationBasis: prescription.normalizationBasis || null,
      prescriptionStatus: prescription.prescriptionStatus || null,
      sourceNotes: prescription.sourceNotes || null,
      explicitImagePlaneSurfaceNumber: Number.isFinite(numericValue(prescription.explicitImagePlaneSurfaceNumber))
        ? Math.round(numericValue(prescription.explicitImagePlaneSurfaceNumber))
        : null,
      imagePlaneSource: prescription.imagePlaneSource || null,
      finalSurfaceRole: prescription.finalSurfaceRole || null,
      diameterSource: prescription.diameterSource || null,
      diameterReference: prescription.diameterReference || null,
      diameterNote: prescription.diameterNote || "",
      diameterProfile: normalizeDiameterProfile(prescription.diameterProfile),
      apertureStopSpec: normalizeApertureStopSpec(prescription.apertureStopSpec),
      derivedApertureStopSpec: normalizeApertureStopSpec(prescription.derivedApertureStopSpec),
      surfaces: (prescription.surfaces || []).map(normalizePatentSurface)
    };
  }

  if (prescription.prescriptionType === "visualOnly") {
    const svgReference = normalizeSvgReference(
      prescription.svgReference || prescription.visualLayout?.svgReference || null
    );
    return {
      prescriptionType: "visualOnly",
      focalLength: normalizePatentSurfaceValue(prescription.focalLength),
      apertureRatio: prescription.apertureRatio ?? null,
      sourceType: "visualReference",
      linkedOpticalPresetKey: prescription.linkedOpticalPresetKey || null,
      note: prescription.note || "",
      svgReference,
      visualLayout: {
        elements: (prescription.visualLayout?.elements || []).map((element, index) => ({
          id: element.id || `visual-${index + 1}`,
          groupIndex: Number.isFinite(toNumber(element.groupIndex)) ? toNumber(element.groupIndex) : index,
          label: element.label || `L${index + 1}`,
          shape: element.shape || "meniscus",
          width: Math.max(0.5, normalizePatentSurfaceValue(element.width) ?? normalizePatentSurfaceValue(element.thickness) ?? 4),
          diameter: Math.max(5, normalizePatentSurfaceValue(element.diameter) ?? 28),
          gapAfter: Math.max(0, normalizePatentSurfaceValue(element.gapAfter) ?? 0),
          frontCurve: element.frontCurve || "convex-left",
          rearCurve: element.rearCurve || "convex-right",
          bevelSize: Math.max(0, normalizePatentSurfaceValue(element.bevelSize) ?? 0.25),
          r1: normalizePatentSurfaceValue(element.r1) ?? 40,
          r2: normalizePatentSurfaceValue(element.r2) ?? -40,
          thickness: Math.max(0.5, normalizePatentSurfaceValue(element.thickness) ?? normalizePatentSurfaceValue(element.width) ?? 4)
        })),
        displayDirection: prescription.visualLayout?.displayDirection || "objectToImage",
        visualOnly: prescription.visualLayout?.visualOnly !== false,
        showRays: prescription.visualLayout?.showRays === true,
        showSensor: prescription.visualLayout?.showSensor === true,
        showFlange: prescription.visualLayout?.showFlange === true,
        showBfd: prescription.visualLayout?.showBfd === true,
        showFullFrameReference: prescription.visualLayout?.showFullFrameReference === true,
        background: prescription.visualLayout?.background || "plain",
        axisStyle: prescription.visualLayout?.axisStyle || "dashed",
        svgReference,
        stop: prescription.visualLayout?.stop ? {
          afterElement: prescription.visualLayout.stop.afterElement || null,
          diameter: Math.max(1, normalizePatentSurfaceValue(prescription.visualLayout.stop.diameter) ?? 20),
          style: prescription.visualLayout.stop.style || "two-dashed-bars"
        } : null
      }
    };
  }

  return {
    prescriptionType: "element",
    sourceType: prescription.sourceType || null,
    sourcePatent: prescription.sourcePatent || null,
    example: prescription.example || null,
    derivedFromPreset: prescription.derivedFromPreset || null,
    derivedFromDesignName: prescription.derivedFromDesignName || null,
    derivedAt: prescription.derivedAt || null,
    retargetSourceEfl: normalizePatentSurfaceValue(prescription.retargetSourceEfl),
    retargetTargetEfl: normalizePatentSurfaceValue(prescription.retargetTargetEfl),
    retargetTargetFNumber: normalizePatentSurfaceValue(prescription.retargetTargetFNumber),
    retargetSensorFormatKey: prescription.retargetSensorFormatKey || null,
    provenance: prescription.provenance || null,
    apertureStopSpec: normalizeApertureStopSpec(prescription.apertureStopSpec),
    derivedApertureStopSpec: normalizeApertureStopSpec(prescription.derivedApertureStopSpec),
    lenses: (prescription.lenses || []).map((lens) => normalizePresetLens({
      id: lens.id || crypto.randomUUID(),
      ...lens
    }))
  };
};

const clonePresetPrescription = (presetKey) => {
  const preset = PRESETS[presetKey] || PRESETS[DEFAULT_PRESET_KEY];
  if (preset.prescriptionType === "surface") {
    return normalizePrescription({
      prescriptionType: "surface",
      focalLength: preset.focalLength,
      apertureRatio: preset.apertureRatio,
      backFocalLength: preset.backFocalLength,
      fieldAngleDeg: preset.fieldAngleDeg,
      imageFormat: preset.imageFormat,
      sourcePatent: preset.sourcePatent,
      example: preset.example,
      patentDataStatus: preset.patentDataStatus,
      presetGroup: preset.presetGroup || null,
      sourceExample: preset.sourceExample || null,
      normalizationBasis: preset.normalizationBasis || null,
      prescriptionStatus: preset.prescriptionStatus || null,
      sourceNotes: preset.sourceNotes || null,
      explicitImagePlaneSurfaceNumber: preset.explicitImagePlaneSurfaceNumber ?? null,
      imagePlaneSource: preset.imagePlaneSource || null,
      finalSurfaceRole: preset.finalSurfaceRole || null,
      diameterSource: preset.diameterSource || null,
      diameterReference: preset.diameterReference || null,
      diameterNote: preset.diameterNote || "",
      diameterProfile: preset.diameterProfile || null,
      numericalAudit: preset.numericalAudit || null,
      apertureStopSpec: preset.apertureStopSpec || null,
      surfaces: preset.surfaces || []
    });
  }

  if (preset.prescriptionType === "visualOnly") {
    return normalizePrescription({
      prescriptionType: "visualOnly",
      focalLength: preset.focalLength,
      apertureRatio: preset.apertureRatio,
      linkedOpticalPresetKey: preset.linkedOpticalPresetKey || null,
      note: preset.note || "",
      svgReference: preset.svgReference || preset.visualLayout?.svgReference || null,
      visualLayout: preset.visualLayout || { elements: [] }
    });
  }

  return normalizePrescription({
    prescriptionType: "element",
    lenses: preset.lenses || []
  });
};

const visualLayoutToLenses = (prescription = {}) => (
  prescription?.prescriptionType === "visualOnly" ? [] : []
);

const prescriptionToLenses = (prescription) => (
  prescription?.prescriptionType === "element"
    ? prescription.lenses.map((lens) => normalizeLens({ ...lens, id: lens.id || crypto.randomUUID() }))
    : prescription?.prescriptionType === "visualOnly"
      ? visualLayoutToLenses(prescription)
      : surfacePrescriptionToDerivedLenses(prescription)
);

const clonePresetLenses = (presetKey) => prescriptionToLenses(clonePresetPrescription(presetKey));

const loadSavedDesigns = () => {
  try {
    return JSON.parse(localStorage.getItem(STORAGE_KEY)) || [];
  } catch {
    return [];
  }
};

let indexedDbPromise = null;

const hasIndexedDb = () => typeof indexedDB !== "undefined";

const openLensDesignDb = () => {
  if (!hasIndexedDb()) return Promise.resolve(null);
  if (indexedDbPromise) return indexedDbPromise;
  indexedDbPromise = new Promise((resolve) => {
    const request = indexedDB.open(INDEXED_DB_NAME, INDEXED_DB_VERSION);
    request.onupgradeneeded = () => {
      const db = request.result;
      Object.values(INDEXED_DB_STORES).forEach((storeName) => {
        if (!db.objectStoreNames.contains(storeName)) {
          db.createObjectStore(storeName, { keyPath: "id" });
        }
      });
    };
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => resolve(null);
    request.onblocked = () => resolve(null);
  });
  return indexedDbPromise;
};

const idbTransaction = async (storeName, mode, callback) => {
  const db = await openLensDesignDb();
  if (!db) return null;
  return new Promise((resolve) => {
    const transaction = db.transaction(storeName, mode);
    const store = transaction.objectStore(storeName);
    let callbackResult = null;
    try {
      callbackResult = callback(store);
    } catch (error) {
      resolve(null);
      return;
    }
    transaction.oncomplete = () => resolve(callbackResult);
    transaction.onerror = () => resolve(null);
    transaction.onabort = () => resolve(null);
  });
};

const idbGetAll = async (storeName) => {
  const db = await openLensDesignDb();
  if (!db) return [];
  return new Promise((resolve) => {
    const transaction = db.transaction(storeName, "readonly");
    const request = transaction.objectStore(storeName).getAll();
    request.onsuccess = () => resolve(request.result || []);
    request.onerror = () => resolve([]);
  });
};

const idbPutAll = async (storeName, records) => idbTransaction(storeName, "readwrite", (store) => {
  (records || []).forEach((record) => store.put(record));
  return true;
});

const idbDelete = async (storeName, id) => idbTransaction(storeName, "readwrite", (store) => {
  store.delete(id);
  return true;
});

const idbPutMetadata = async (id, value) => idbPutAll(INDEXED_DB_STORES.metadata, [{ id, value, updatedAt: new Date().toISOString() }]);

const idbGetMetadata = async (id) => {
  const db = await openLensDesignDb();
  if (!db) return null;
  return new Promise((resolve) => {
    const transaction = db.transaction(INDEXED_DB_STORES.metadata, "readonly");
    const request = transaction.objectStore(INDEXED_DB_STORES.metadata).get(id);
    request.onsuccess = () => resolve(request.result?.value ?? null);
    request.onerror = () => resolve(null);
  });
};

const migrateLocalStorageSavedDesignsToIndexedDb = async () => {
  if (!hasIndexedDb()) return { migrated: false, count: 0 };
  const alreadyMigrated = await idbGetMetadata("localStorageMigrationComplete");
  const localDesigns = loadSavedDesigns();
  if (alreadyMigrated || !localDesigns.length) return { migrated: false, count: 0 };
  const existing = await idbGetAll(INDEXED_DB_STORES.designs);
  const existingIds = new Set(existing.map((design) => design.id));
  const records = localDesigns
    .filter((design) => design?.id && !existingIds.has(design.id))
    .map((design) => ({
      ...design,
      schemaVersion: design.schemaVersion || PROJECT_SCHEMA_VERSION,
      migratedFrom: "localStorage",
      migratedAt: new Date().toISOString()
    }));
  if (records.length) await idbPutAll(INDEXED_DB_STORES.designs, records);
  await idbPutMetadata("localStorageMigrationComplete", true);
  return { migrated: records.length > 0, count: records.length };
};

const refreshSavedDesignsFromIndexedDb = async () => {
  const designs = await idbGetAll(INDEXED_DB_STORES.designs);
  if (!designs.length) return false;
  state.savedDesigns = designs
    .filter((design) => design && design.id)
    .sort((a, b) => String(b.updatedAt || "").localeCompare(String(a.updatedAt || "")));
  return true;
};

const initPersistentStorage = async () => {
  const migration = await migrateLocalStorageSavedDesignsToIndexedDb();
  const loaded = await refreshSavedDesignsFromIndexedDb();
  state.storageStatus = {
    backend: hasIndexedDb() ? "indexedDB" : "localStorage",
    migration
  };
  if (loaded || migration.migrated) update({ scope: "storage-init" });
};

const persistAnalysisCacheMetadata = () => {
  if (!hasIndexedDb()) return;
  idbPutAll(INDEXED_DB_STORES.analysisCache, [{
    id: "active-analysis-cache",
    revision: state.analysisCacheRevision || 0,
    mtfSignature: state.mtfAnalysis?.signature || "",
    mainMtfCacheSize: mainMtfResultCache.size,
    apertureSweepCacheSize: apertureSweepResultCache.size,
    diffractionCacheSize: diffractionMtfResultCache.size,
    updatedAt: new Date().toISOString()
  }]);
};

const persistOptimizerReport = (result = state.optimizerBest) => {
  if (!hasIndexedDb() || !result) return;
  idbPutAll(INDEXED_DB_STORES.optimizerReports, [{
    id: `optimizer-${Date.now()}`,
    designName: state.designName || PRESETS[state.preset]?.name || "Untitled design",
    preset: state.preset,
    result,
    csv: exportOptimizerCsv(result),
    updatedAt: new Date().toISOString()
  }]);
};

const persistCsvExport = (kind, text) => {
  if (!hasIndexedDb() || !text) return;
  idbPutAll(INDEXED_DB_STORES.csvExports, [{
    id: `${kind}-${Date.now()}`,
    kind,
    text,
    preset: state.preset,
    designName: state.designName || "",
    updatedAt: new Date().toISOString()
  }]);
};

const persistSvgReferenceMetadata = () => {
  if (!hasIndexedDb()) return;
  const reference = getProductionSvgReferenceForPreset(PRESETS[state.preset]);
  if (!reference) return;
  idbPutAll(INDEXED_DB_STORES.svgReferences, [{
    id: state.preset || "active",
    preset: state.preset,
    href: reference.href || "",
    viewBox: reference.viewBox || "",
    updatedAt: new Date().toISOString()
  }]);
};

